var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사실 공고 잘못 보고 시작한 일을 이렇게 오래 하게 될 줄은 상상도 못했어요.","JPN":"実は、募集を見間違えて始めた仕事をここまで長く続けるとは思っていませんでした。","ENG":"To be honest, I didn't think I'd be working a job I applied for by mistake for this long.","TWN":"其實我當初是看錯公告才過來的，根本沒想到這份工作會做這麼久。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뉴스에서는 태스크포스 업계가 성황이라던데, 사실 평범한 사람들 입장에서는 다른 세상 이야기 같잖아요.","JPN":"ニュースでタスクフォースカンパニー業界が盛況だと取り上げられていますが、一般人としては別世界の話ですよね。","ENG":"News says the TASKFORCE business is doing amazingly well these days, but to ordinary people, it feels a long way away.","TWN":"雖然新聞總是報導特遣勢力的繁華盛況，但對普通人而言，那完全是另一個世界的事情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저도 그랬어요. 아니, 지금도 그래요.","JPN":"僕もそうでした。いや、今もそうです。","ENG":"I was just like any of them. No, I mean I still am.","TWN":"我曾經也這樣覺得。不，現在也一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"현장에 급히 출동한다거나, 침식체와 싸울 일이 생기면 여전히 낯설게 느껴져요.","JPN":"急いで現場に出動したり、侵食体と戦うことは、\\nいまだに慣れません。","ENG":"It feels surreal that I'm the one that's being dispatched to the scene, or that I'm the one that's fighting the C.O.s.","TWN":"無論是緊急前往現場，還是與侵蝕體戰鬥，我都還沒有習慣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나 여기 있어도 정말 괜찮은 건가......? 같은 느낌?","JPN":"僕、ここにいて本当にいいのかな……？\\nみたいな感じ？","ENG":"\\"Am I really okay to be here?\\" You know, that kind of stuff.","TWN":"我在這裡真的沒問題嗎……就像這樣的感覺吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐, 그래도 사장님이랑 이렇게 친해졌는데 나 몰라라 등 돌리면 섭섭하잖아요.","JPN":"まあでも、社長とこんなに仲良くなったのに、今さら知らん顔して背を向けるのは寂しいじゃないですか。","ENG":"But we're close now, and it'd be rude of me if I just walked away, wouldn't it?","TWN":"不過，我和老闆都變得這麼熟了，這樣不理不睬會很傷人吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사실 아르바이트 하다 보면, 학교에선 인간관계가 설렁설렁해지거든요.","JPN":"正直、バイトなんかやってると学校での人間関係がうまくいかないんです。","ENG":"Students working part time don't actually mix well in school.","TWN":"其實，當我開始打工時，在學校裡的人際關係就疏遠了起來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"게다가 전 원래 배경 역할이었다 보니...... 카운터가 됐다고 <color=#ffd34c>나유카 군! 카운터가 됐다면서?!</color> 라고 몰려드는 시츄에이션은 안 일어나더라고요.","JPN":"そもそも僕は学校で存在感が薄くて……カウンターになってからも\\n<color=#ffd34c>奈由香君！カウンターになったんだって？</color>と友達が押し寄せたりはしませんでした。","ENG":"I've always been a nobody among my peers, and no one came crying, \\"<color=#ffd34c>Nayuka! Are you really a Counter?</color>\\" just because I became a Counter.","TWN":"再加上我本來就是個路人甲……成為了制裁者後， 一群人擠過來，說：<color=#ffd34c>南裕夏君！聽說你成為制裁者了？！</color>之類的情況都沒有發生。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"기껏 해 봐야 뒤에서 수군대는 정도랄지. 하아...","JPN":"みんな陰でこそこそするくらいでしたね。はあ……","ENG":"All they did was talk behind my back. *Sigh*","TWN":"他們頂多就是在背後竊竊私語。唉……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래서 기왕이면 사장님과 더 오래 지내면 좋겠어요.","JPN":"だから、どうせなら社長とずっと仲良しでいたいですね。","ENG":"And that's why I want to be around you, at least for now.","TWN":"所以我希望能和老闆相處得更久。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이를테면...... 좋은 친구 사이라도 괜찮으니까요.","JPN":"例えば……親友とかどうでしょうか。","ENG":"I mean, it doesn't have to be an employer-employee relationship. It'd be enough for me if we just could be good friends.","TWN":"就像是……好朋友之間的關係。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};